const { ethers } = require("ethers");
require("dotenv").config();

// XCM Message generated by calc_xcm_message.js
const XCM_MESSAGE_HEX = "";

// XCM Precompile on Asset Hub
const XCM_PRECOMPILE = "0x0000000000000000000000000000000000000804";

// Asset Hub RPC
const ASSET_HUB_RPC = "https://eth-rpc.polkadot.io/";

async function main() {
    console.log("=== Test Execute XCM ===\n");

    const provider = new ethers.JsonRpcProvider(ASSET_HUB_RPC);

    // Check if we can call the precompile
    const code = await provider.getCode(XCM_PRECOMPILE);
    console.log("Precompile bytecode at 0x804:", code ? "EXISTS" : "NONE");

    // Try different precompile addresses
    const addresses = [
        "0x0000000000000000000000000000000000000800",
        "0x0000000000000000000000000000000000000801",
        "0x0000000000000000000000000000000000000802",
        "0x0000000000000000000000000000000000000803",
        "0x0000000000000000000000000000000000000804",
        "0x0000000000000000000000000000000000000805",
    ];

    console.log("\nChecking precompile code at various addresses:");
    for (const addr of addresses) {
        try {
            const codeCheck = await provider.getCode(addr);
            const hasCode = codeCheck && codeCheck !== "0x";
            console.log(`  ${addr}: ${hasCode ? "✅ Has code" : "❌ No code"}`);
        } catch (e) {
            console.log(`  ${addr}: ❌ Error - ${e.message}`);
        }
    }

    // Try execute with generous weight (Weight First signature)
    // function execute(uint64 refTime, uint64 proofSize, bytes message)
    console.log("\n--- Testing execute with Weight First signature ---");
    const iface = new ethers.Interface([
        "function execute(uint64 refTime, uint64 proofSize, bytes memory message) returns (bytes)"
    ]);

    const refTime = 10000000000n;  // 10 billion
    const proofSize = 500000n;     // 500k

    const callData = iface.encodeFunctionData("execute", [refTime, proofSize, XCM_MESSAGE_HEX]);
    console.log("Execute selector:", callData.slice(0, 10));

    // Dry-run via eth_call (won't actually execute but will show if it would revert)
    try {
        // Need a wallet to simulate execution
        const wallet = new ethers.Wallet(process.env.ASSET_PK, provider);

        const result = await wallet.call({
            to: XCM_PRECOMPILE,
            data: callData
        });
        console.log("✅ execute() dry-run result:", result);
    } catch (e) {
        console.log("❌ execute() dry-run error:", e.message);
        if (e.data) console.log("   Revert data:", e.data);
    }

    console.log("\n=== Test Complete ===");
}

main().catch(console.error);
